import{_ as r,o as e,c as a,aw as s}from"./chunks/framework.DLufY-ao.js";const o="/workbook/assets/graph1.BQUCDHBg.png",i="/workbook/assets/graph2.Cx1YQbwE.png",m=JSON.parse('{"title":"Graph (Граф)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/graph.md","filePath":"wiki/dev-commit/theory/data-structures/structures/graph.md"}'),l={name:"wiki/dev-commit/theory/data-structures/structures/graph.md"};function d(h,t,n,c,g,u){return e(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="graph-граф" tabindex="-1">Graph (Граф) <a class="header-anchor" href="#graph-граф" aria-label="Permalink to &quot;Graph (Граф)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><img src="'+o+'" width="450px"><div class="tip custom-block"><p class="custom-block-title">Граф</p><ul><li><strong>Граф</strong> - совокупности узлов (вершин) и связей между ними (рёбер). Также их называют сетями</li><li>По такому принципу устроены социальные сети: узлы — это люди, а рёбра — их отношения</li></ul></div><h2 id="типы-графов" tabindex="-1">Типы графов <a class="header-anchor" href="#типы-графов" aria-label="Permalink to &quot;Типы графов&quot;">​</a></h2><ul><li><strong>Ориентированные</strong> - рёбра между узлами не имеют направление</li><li><strong>Неориентированные</strong> - рёбра между узлами не имеют какого-либо направления</li></ul><blockquote><p>Чаще всего граф изображают в каком-либо из двух видов: это может быть список смежности или матрица смежности</p></blockquote><img src="'+i+'" width="450px"><div class="tip custom-block"><p class="custom-block-title">Список смежности</p><ul><li><strong>Список смежности</strong> - можно представить как перечень элементов, где слева находится один узел, а справа — все остальные узлы, с которыми он соединяется</li><li><strong>Матрица смежности</strong> - это сетка с числами, где каждый ряд или колонка соответствуют отдельному узлу в графе. На пересечении ряда и колонки находится число, которое указывает на наличие связи. Нули означают, что она отсутствует; единицы — что связь есть. Чтобы обозначить вес каждой связи, используют числа больше единицы</li><li><strong>Алгоритмы обхода</strong> - лгоритмы для просмотра рёбер и вершин в графах. К их основным типам относят <em>&quot;Поиск в ширину&quot;</em> (breadth-first search) и <em>&quot;Поиск в глубину&quot;</em> (depth-first search). Как вариант, с их помощью можно определить, насколько близко к корневому узлу находятся те или иные вершины графа</li></ul></div><h2 id="сложность-алгоритма" tabindex="-1">Сложность алгоритма <a class="header-anchor" href="#сложность-алгоритма" aria-label="Permalink to &quot;Сложность алгоритма&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Алгоритм</th><th style="text-align:right;">Время</th></tr></thead><tbody><tr><td>Storage</td><td style="text-align:right;">O(|V|+|E|)</td></tr><tr><td>Add Vertex</td><td style="text-align:right;">O(1)</td></tr><tr><td>Add Edge</td><td style="text-align:right;">O(1)</td></tr><tr><td>Remove Vertex</td><td style="text-align:right;">O(|V|+|E|)</td></tr><tr><td>Remove Edge</td><td style="text-align:right;">O(|E|)</td></tr><tr><td>Query</td><td style="text-align:right;">O(|V|)</td></tr></tbody></table>',11)])])}const _=r(l,[["render",d]]);export{m as __pageData,_ as default};
